LAYER
	NAME "comercio"
	GROUP "MPU"
	TYPE polygon
	PROCESSING "LABEL_NO_CLIP=1"
	#HEADER "plantillas/inicio.html"
	#TEMPLATE "plantillas/mpu/mpu/comercio.html"
	#FOOTER "plantillas/fin.html"
	STATUS on
	DATA "geom FROM (SELECT gid, codi_piso, area_grafi, codi_lote, id_uni_cat, fech_actua, id_lote, id_constru, nume_ficha, geom FROM geo.tg_comercio) as mpu using unique gid using srid=32718"
	INCLUDE "configuracion/postgresql_mpu.map"
	PROJECTION
		"init=epsg:32718"
	END
	CLASSITEM "gid"
	METADATA
		"wms_group_title" "MPU"
		"queryable" "true"
		"wms_metadataurl_href" ""
		"wms_metadataurl_format" "text/xml"
		"wms_metadataurl_type" "TC211"
		"wms_title" "Comercio"
		"wms_abstract" "Comercio || Municipalidad Provincial de Urubamba - Cusco :: Perú"
		"wms_credit" "MPU"
		"wms_dataurl" ""
		"wms_dataurl_format" "text/html"
		"wms_dataurl_href" ""
		"wms_extent" "807683.9653000003 8526364.0129 814882.6846000003 8531884.0174"
		"wms_srs" "EPSG:32718"
		"wms_include_items" "all"
		"wms_exclude_items" "gid"
	END
	CLASS
		NAME "Comercio"
		EXPRESSION /./
		STYLE
			COLOR 219 117 102
			OUTLINECOLOR 158 45 35
			WIDTH 1
		END
	END
END # Layer